from __future__ import annotations

import html
import json
from pathlib import Path

from . import __version__
from .locales import PRESENTATION_LABELS


def esc(value: object, limit: int = 640) -> str:
    text = " ".join(str(value or "").split())
    if len(text) > limit:
        text = text[: limit - 1].rstrip() + "\u2026"
    return html.escape(text)


def render_html(summary: dict, *, title: str, subtitle: str = "") -> str:
    language = summary.get("language", "en")
    labels = PRESENTATION_LABELS.get(language, PRESENTATION_LABELS["en"])
    outputs = summary.get("outputs", [])
    agents = summary.get("source_agents", [])
    slides: list[str] = []
    slides.append(f'''<section class="slide cover active" data-title="{esc(title)}"><div class="cover-left"><div class="meta">AGENT WORK REVIEW - {esc(__version__)}</div><h1>{esc(title, 180)}</h1><p>{esc(subtitle or labels['review'], 260)}</p></div><div class="cover-right"><div><span class="big">{len(outputs):02d}</span><span class="caption">OUTPUTS</span></div><div><span class="big">{len(agents):02d}</span><span class="caption">AGENT SOURCES</span></div><div class="agent-list">{esc(' / '.join(agents) or 'manual')}</div></div></section>''')
    overview_items = "".join(f'<li><span>{index:02d}</span><strong>{esc(item.get("title"), 120)}</strong><small>{esc(item.get("workspace"), 80)}</small></li>' for index, item in enumerate(outputs, 1)) or '<li><span>00</span><strong>No reviewed outputs yet</strong><small>Import evidence and rebuild</small></li>'
    executive = str(summary.get("executive_summary") or "").strip()
    executive_html = f'<p class="executive-summary">{esc(executive, 520)}</p>' if executive else ""
    slides.append(f'''<section class="slide" data-title="{esc(labels['overview'])}"><div class="chrome"><span>{esc(labels['overview']).upper()}</span><span>02 / {len(outputs)+3:02d}</span></div><h2>{esc(labels['overview'])}</h2>{executive_html}<ol class="overview">{overview_items}</ol></section>''')
    for index, item in enumerate(outputs, 1):
        slide_no = index + 2
        sources = " / ".join(item.get("source_agents") or ["generic"])
        slides.append(f'''<section class="slide" data-title="{esc(item.get('title'))}"><div class="chrome"><span>OUTPUT {index:02d}</span><span>{slide_no:02d} / {len(outputs)+3:02d}</span></div><div class="item-head"><div><div class="eyebrow">{esc(item.get('evidence_level')).upper()} - {esc(item.get('workspace'), 100)}</div><h2>{esc(item.get('title'), 180)}</h2></div><div class="source-pill">{esc(sources, 100)}</div></div><div class="quad"><article><label>{esc(labels['background'])}</label><p>{esc(item.get('background'))}</p></article><article><label>{esc(labels['content'])}</label><p>{esc(item.get('content'))}</p></article><article class="accent"><label>{esc(labels['impact'])}</label><p>{esc(item.get('impact'))}</p></article><article><label>{esc(labels['next'])}</label><p>{esc(item.get('next_plan'))}</p></article></div></section>''')
    slides.append(f'''<section class="slide closing" data-title="End"><div class="meta">AGENT WORK REVIEW</div><h2>{esc(labels['close'], 200)}</h2><div class="rule"></div><p>{esc(title, 180)}</p></section>''')
    slides_json = json.dumps([str(item.get("title") or f"Output {i}") for i, item in enumerate(outputs, 1)], ensure_ascii=False).replace("<", "\\u003c").replace(">", "\\u003e").replace("&", "\\u0026")
    return f'''<!doctype html><html lang="{language}"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{esc(title)}</title><style>
:root{{--paper:#f7f7f3;--ink:#111214;--muted:#676b70;--line:#d5d7d8;--accent:#1346d8;--soft:#e8e9e7}}*{{box-sizing:border-box}}html,body{{margin:0;width:100%;height:100%;overflow:hidden;background:var(--ink);font-family:Helvetica,"Noto Sans SC","Microsoft YaHei UI",sans-serif;color:var(--ink)}}.slide{{display:none;position:absolute;inset:0;background:var(--paper);padding:5.5vh 5vw 8vh;overflow:hidden}}.slide.active{{display:flex;flex-direction:column}}.cover{{padding:0;display:none;grid-template-columns:7fr 5fr}}.cover.active{{display:grid}}.cover-left{{background:var(--accent);color:white;padding:6vh 5vw;display:flex;flex-direction:column;justify-content:space-between}}.cover h1{{font-size:min(8vw,14vh);line-height:.94;font-weight:200;letter-spacing:0;margin:8vh 0 0;max-width:10ch}}.cover p{{font-size:clamp(18px,1.6vw,30px);max-width:36ch}}.meta,.chrome,.eyebrow,label,.caption{{font-family:ui-monospace,SFMono-Regular,Consolas,monospace;font-size:clamp(12px,.78vw,15px);font-weight:600;letter-spacing:.12em;text-transform:uppercase}}.cover-right{{background:#fff;padding:6vh 4vw;display:grid;align-content:center;gap:5vh}}.cover-right>div{{border-top:1px solid var(--line);padding-top:2vh}}.big{{display:block;font-size:min(10vw,16vh);font-weight:200;line-height:.9}}.caption{{color:var(--muted)}}.agent-list{{font-size:clamp(16px,1.2vw,22px)}}.chrome{{display:flex;justify-content:space-between;color:var(--muted);border-bottom:1px solid var(--line);padding-bottom:1.2vh}}h2{{font-size:min(5.6vw,9vh);font-weight:250;line-height:1;letter-spacing:0;margin:4vh 0}}.overview{{list-style:none;padding:0;margin:2vh 0;display:grid;grid-template-columns:1fr 1fr;gap:0 4vw;overflow:hidden}}.overview li{{display:grid;grid-template-columns:3.5em 1fr;grid-template-rows:auto auto;border-top:1px solid var(--line);padding:1.5vh 0;min-height:7vh}}.overview span{{grid-row:1/3;font-size:clamp(24px,2.4vw,46px);font-weight:250;color:var(--accent)}}.overview strong{{font-size:clamp(15px,1.12vw,21px);font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}}.overview small{{color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}}.item-head{{display:grid;grid-template-columns:1fr auto;gap:2vw;align-items:end}}.item-head h2{{margin:1.4vh 0 3vh;max-width:18ch}}.eyebrow{{color:var(--accent)}}.source-pill{{border:1px solid var(--line);padding:1vh 1vw;font-size:14px;margin-bottom:3vh;max-width:26vw;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}}.quad{{display:grid;grid-template-columns:1fr 1fr;grid-template-rows:1fr 1fr;gap:1px;background:var(--line);flex:1;min-height:0}}article{{background:#fff;padding:2.2vh 1.5vw;overflow:hidden}}article.accent{{background:var(--accent);color:#fff}}article label{{display:block;color:var(--muted);margin-bottom:1.2vh}}article.accent label{{color:rgba(255,255,255,.72)}}article p{{font-size:clamp(15px,1.15vw,21px);line-height:1.52;margin:0;display:-webkit-box;-webkit-line-clamp:5;-webkit-box-orient:vertical;overflow:hidden}}.closing{{background:var(--accent);color:#fff;justify-content:space-between}}.closing h2{{font-size:min(8vw,14vh);max-width:12ch;margin:auto 0;font-weight:200}}.closing .rule{{height:1px;background:rgba(255,255,255,.4)}}#nav{{position:fixed;left:5vw;right:5vw;bottom:2.5vh;color:white;display:flex;justify-content:space-between;z-index:20;font:600 12px ui-monospace,monospace;letter-spacing:.12em}}#index{{display:none;position:fixed;inset:0;background:rgba(17,18,20,.96);color:#fff;z-index:30;padding:6vh 5vw;overflow:auto}}#index.open{{display:block}}#index-grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:1px;background:#444}}#index button{{border:0;background:#222;color:#fff;padding:2rem;text-align:left;min-height:130px;cursor:pointer}}#index button:hover{{background:var(--accent)}}@media(max-width:760px){{.cover.active{{grid-template-columns:1fr}}.cover-right{{grid-template-columns:1fr 1fr;padding:4vh 5vw}}.cover h1{{font-size:min(14vw,10vh)}}.overview{{grid-template-columns:1fr}}.quad{{grid-template-columns:1fr;grid-template-rows:repeat(4,1fr)}}article p{{-webkit-line-clamp:3}}.source-pill{{display:none}}}}@media print{{body{{overflow:visible}}.slide{{display:flex!important;position:relative;width:100vw;height:56.25vw;page-break-after:always}}#nav,#index{{display:none!important}}}}
</style><style>.executive-summary{{max-width:72ch;font-size:clamp(16px,1.25vw,23px);line-height:1.55;color:var(--muted);margin:-1.5vh 0 2vh}}</style></head><body><main id="deck">{''.join(slides)}</main><div id="nav" style="color:#111214;background:rgba(247,247,243,.92);border-top:1px solid #d5d7d8;padding:.7vh 1vw"><span id="counter"></span><span>{esc(labels['hint'])}</span></div><div id="index"><div id="index-grid"></div></div><script>
const slides=[...document.querySelectorAll('.slide')],counter=document.getElementById('counter'),overlay=document.getElementById('index'),grid=document.getElementById('index-grid');let current=0;const names={slides_json};function show(i){{current=(i+slides.length)%slides.length;slides.forEach((s,n)=>s.classList.toggle('active',n===current));counter.textContent=String(current+1).padStart(2,'0')+' / '+String(slides.length).padStart(2,'0')}}slides.forEach((s,i)=>{{const b=document.createElement('button');b.textContent=String(i+1).padStart(2,'0')+'  '+(s.dataset.title||names[i-2]||'Slide');b.onclick=()=>{{overlay.classList.remove('open');show(i)}};grid.appendChild(b)}});addEventListener('keydown',e=>{{if(e.key==='ArrowRight'||e.key==='PageDown'||e.key===' ')show(current+1);if(e.key==='ArrowLeft'||e.key==='PageUp')show(current-1);if(e.key==='Escape')overlay.classList.toggle('open')}});let x=0;addEventListener('touchstart',e=>x=e.touches[0].clientX,{{passive:true}});addEventListener('touchend',e=>{{const d=e.changedTouches[0].clientX-x;if(Math.abs(d)>40)show(current+(d<0?1:-1))}},{{passive:true}});show(0);
</script></body></html>'''


def write_html(summary: dict, output: Path, *, title: str, subtitle: str = "") -> Path:
    output.parent.mkdir(parents=True, exist_ok=True)
    output.write_text(render_html(summary, title=title, subtitle=subtitle), encoding="utf-8")
    return output
